function togClass(t,e){if("string"==typeof t){[...document.querySelectorAll(t)].forEach(t=>t.classList.toggle(e));return}t.classList.toggle(e)}function addClass(t,e){if("string"==typeof t){[...document.querySelectorAll(t)].forEach(t=>t.classList.add(e));return}t.classList.add(e)}function remClass(t,e){if("string"==typeof t){[...document.querySelectorAll(t)].forEach(t=>t.classList.remove(e));return}t.classList.remove(e)}function togAttr(t,e){if("string"==typeof t){[...document.querySelectorAll(t)].forEach(t=>t.toggleAttribute(e));return}t.toggleAttribute(e)}function setAttr(t,e,r){if("string"==typeof t){[...document.querySelectorAll(t)].forEach(t=>t.setAttribute(e,r));return}t.toggleAttribute(e,r)}function log(t){console.log(t)}
